#version 300 es
precision highp float;

// VisualSynth uniforms
uniform float uTime;
uniform float uFrame;
uniform float uFps;
uniform float uRms;

// Audio uniforms
uniform float audioLow;      // bass
uniform float audioLowSmooth; // bass_att
uniform float audioMid;      // mid
uniform float audioMidSmooth; // mid_att
uniform float audioHigh;     // treb
uniform float audioHighSmooth; // treb_att

// Screen uniforms
uniform float uAspectX;
uniform float uAspectY;
uniform vec2 uAspect;
uniform vec2 uTexSize;

// Random values
uniform vec2 uRandomPreset;
uniform vec2 uRandomFrame;

// Input from vertex shader
in vec2 vUv;
in float vRadius;
in float vAngle;

// Output
out vec4 fragColor;

// Textures
uniform sampler2D sampler_main;
uniform sampler2D sampler_noise_lq;
uniform sampler2D sampler_noise_mq;
uniform sampler2D sampler_noise_hq;
uniform sampler2D sampler_blur1;
uniform sampler2D sampler_blur2;
uniform sampler2D sampler_blur3;

// Helper functions
float clamp01(float x) { return clamp(x, 0.0, 1.0); }
vec2 clamp01(vec2 x) { return clamp(x, vec2(0.0), vec2(1.0)); }
vec3 clamp01(vec3 x) { return clamp(x, vec3(0.0), vec3(1.0)); }
vec4 clamp01(vec4 x) { return clamp(x, vec4(0.0), vec4(1.0)); }

// Texture helper functions
vec4 GetPixel(vec2 uv) { return texture(sampler_main, uv); }
vec4 GetBlur1(vec2 uv) { return texture(sampler_blur1, uv); }
vec4 GetBlur2(vec2 uv) { return texture(sampler_blur2, uv); }
vec4 GetBlur3(vec2 uv) { return texture(sampler_blur3, uv); }


void main() {
  vec4 ret = vec4(0.0);
  vec2 uv = vUv;
  float rad = vRadius;


uv1 = (vUv-.5);

vec2 ang2= texture(sampler_noise_hq,uv1/3+.006*uTime).xy;
uv6 = multiply(uv1,mat2(ang2.y,-ang2.x,ang2.x,ang2.y));

mus = abs(.5*cos(uv6.y*14)-(cos(uv6.x*71)));
mus *= vec3 (1,.96,.9)/25;

uv6 = .2*sin(12*vUv+rand_frame);
vec3 dots = .001/length(uv6)* vec3 (0.2,1,1);

//dots = lum(texture(sampler_noise_hq,vUv +rand_frame));
//dots = (dots-.7) * (dots >= .7) * vec3 (0.2,1,1);

mus -= dots;


vec3 blur = GetBlur1(fract(vUv));

vec2 hor = vec2 (uTexSize.z,0);
vec2 ver = vec2 (0,uTexSize.w);
hor = vec2 (.004,0);
ver = vec2 (0,.004);



float dx = lum(GetPixel(vUv+hor)-GetPixel(vUv-hor));
float dy = lum(GetPixel(vUv+ver)-GetPixel(vUv-ver));

vec2 zz = vec2 (dx,dy);


vec3 crisp= texture(sampler_main,vUv+zz*.02);
crisp +=.015 - length(zz)*blur/1.5;

vec3 ret1 = crisp - lum(blur)*.012 + mus;
//ret1 = abs(mus)/2;
ret = ret1 * .99 -  .04 ;

  fragColor = ret;
}

_shaderData.comp:
#version 300 es
precision highp float;

// VisualSynth uniforms
uniform float uTime;
uniform float uFrame;
uniform float uFps;
uniform float uRms;

// Audio uniforms
uniform float audioLow;      // bass
uniform float audioLowSmooth; // bass_att
uniform float audioMid;      // mid
uniform float audioMidSmooth; // mid_att
uniform float audioHigh;     // treb
uniform float audioHighSmooth; // treb_att

// Screen uniforms
uniform float uAspectX;
uniform float uAspectY;
uniform vec2 uAspect;
uniform vec2 uTexSize;

// Random values
uniform vec2 uRandomPreset;
uniform vec2 uRandomFrame;

// Input from vertex shader
in vec2 vUv;
in float vRadius;
in float vAngle;

// Output
out vec4 fragColor;

// Textures
uniform sampler2D sampler_main;
uniform sampler2D sampler_noise_lq;
uniform sampler2D sampler_noise_mq;
uniform sampler2D sampler_noise_hq;
uniform sampler2D sampler_blur1;
uniform sampler2D sampler_blur2;
uniform sampler2D sampler_blur3;

// Helper functions
float clamp01(float x) { return clamp(x, 0.0, 1.0); }
vec2 clamp01(vec2 x) { return clamp(x, vec2(0.0), vec2(1.0)); }
vec3 clamp01(vec3 x) { return clamp(x, vec3(0.0), vec3(1.0)); }
vec4 clamp01(vec4 x) { return clamp(x, vec4(0.0), vec4(1.0)); }

// Texture helper functions
vec4 GetPixel(vec2 uv) { return texture(sampler_main, uv); }
vec4 GetBlur1(vec2 uv) { return texture(sampler_blur1, uv); }
vec4 GetBlur2(vec2 uv) { return texture(sampler_blur2, uv); }
vec4 GetBlur3(vec2 uv) { return texture(sampler_blur3, uv); }


void main() {
  vec4 ret = vec4(0.0);
  vec2 uv = vUv;
  float rad = vRadius;

vUv.y = vUv.y-.2*q1;

vec2 uv1 = (vUv-.5 )*uAspect.xy;

float z = .1/uv1.y/uv1.x;
rs0.x = uv1.x*z;
rs0.y = z;
rs = rs0 + uTime/2;

//uv1 = multiply(uv1,mat2(_qa));
noise = lum(texture(sampler_noise_hq,rs/2));
noise = noise-.56;

vec3 mask = clamp01(12*(uv1.y)) ;

/////////////

uv2 = 2*uv1 * abs(pow(sqrt(uv1.x),.3+q10)) ;

uv4 = 8*uv1 * (pow(abs(uv1.x),.4+q25))+vec2(0.5,.5+uTime/8) ;

float mask2 = pow(1-vRadius,8);
mask2 = pow(1-length(2*uv1),8);

uv3 = fract(uv2-.5-.1*noise*mask);

vec2 hor = vec2 (uTexSize.z,0);
vec2 ver = vec2 (0, uTexSize.w);
float dx = lum(GetPixel(uv3+hor) - GetPixel(uv3-hor));
float dy = lum(GetPixel(uv3+ver) - GetPixel(uv3-ver));
vec2 dz = vec2 (dx,dy);

ret1 = 0 ;
ret1 = GetBlur1(fract(uv3))*0 + GetPixel(uv3);
ret1 *= 1-.5*mask;
//////////

ret1 *= .2+ audioLowSmooth/3;

vec2 uv6 = .3*sin(4*uv1) + dz*8;
vec3 mus = ((.06/length(uv6))-.2);

ret = (1-.5*mask2)*ret1*(1+mus)
+ clamp01(q10*(2-8*ret1.r)*mask2*GetPixel(uv4));

  fragColor = ret;
}
